using System.Text.RegularExpressions;

namespace Contoso.Text;

public sealed class StringFormatter
{
    public string FormatPhoneNumber(string digits)
    {
        ArgumentNullException.ThrowIfNull(digits);
        if (digits.Length != 10)
            throw new ArgumentException("Must be exactly 10 digits.", nameof(digits));
        return $"({digits[..3]}) {digits[3..6]}-{digits[6..]}";
    }

    public string BuildGreeting(string name, string title = "Mr.")
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(name);
        return $"Dear {title} {name},";
    }

    public string GenerateSlug(string title)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        return Regex.Replace(title.Trim().ToLowerInvariant(), @"[^a-z0-9]+", "-").Trim('-');
    }

    public string FormatCurrency(decimal amount, string symbol = "$")
    {
        return $"{symbol}{amount:F2}";
    }
}

using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.EndsWith(result, "-4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsSeparatorSpace()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.Contains(result, ") ");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithNameAndComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, "Smith,");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.Contains(result, "Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsFullGreeting()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StartsWithFirstWord()
    {
        var result = _formatter.GenerateSlug("C# is Great!");

        StringAssert.StartsWith(result, "c-");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_EndsWithLastWord()
    {
        var result = _formatter.GenerateSlug("C# is Great!");

        StringAssert.EndsWith(result, "great");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithMultipleSpaces_ContainsHyphens()
    {
        var result = _formatter.GenerateSlug("My   Blog   Post");

        StringAssert.Contains(result, "-");
        Assert.AreEqual("my-blog-post", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_TrimsCleanly()
    {
        var result = _formatter.GenerateSlug("  padded title  ");

        Assert.AreEqual("padded-title", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWith TwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(10m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(5.5m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_ReturnsFullFormat()
    {
        var result = _formatter.FormatCurrency(1234.5m, "£");

        Assert.AreEqual("£1234.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-42.10m);

        StringAssert.Contains(result, "-");
        Assert.AreEqual("$-42.10", result);
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

